class Solution:
    def shipWithinDays(self, weights: List[int], days: int) -> int:
        def can_ship(capacity):
            day, curr_weight = 1, 0
            for weight in weights:
                curr_weight += weight
                if curr_weight > capacity:
                    day += 1
                    curr_weight = weight
            return day <= days

        left, right = max(weights), sum(weights)
        while left < right:
            mid = (left + right) // 2
            if can_ship(mid):
                right = mid
            else:
                left = mid + 1
        return left
